import { useEffect, useRef, useState } from "react";
import "./styles/GlobalSearch.css";

export default function GlobalSearch() {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState(null);
    const [open, setOpen] = useState(false);
    const containerRef = useRef(null);

    // Fetch default results on focus
    const fetchDefault = () => {
        fetch("/api/search")
            .then(r => r.json())
            .then(setResults)
            .catch(() => {});
    };

    // Fetch filtered results
    useEffect(() => {
        if (!open) return;

        if (!query.trim()) {
            fetchDefault();
            return;
        }

        fetch(`/api/search?q=${encodeURIComponent(query)}`)
            .then(r => r.json())
            .then(setResults)
            .catch(() => {});
    }, [query, open]);

    // Close on outside click
    useEffect(() => {
        const handler = e => {
            if (!containerRef.current?.contains(e.target)) {
                setOpen(false);
            }
        };
        document.addEventListener("mousedown", handler);
        return () => document.removeEventListener("mousedown", handler);
    }, []);

    return (
        <div ref={containerRef} className={"global-search"}>
            <input
                placeholder="Search clubs, events, threads…"
                value={query}
                onFocus={() => {
                    setOpen(true);
                    fetchDefault();
                }}
                onChange={e => setQuery(e.target.value)}
                className={"input"}
            />

            <form className="form">
                <label ref="search">
                    <input placeholder="Search clubs, events, threads…"
                           value={query}
                           onFocus={() => {
                               setOpen(true);
                               fetchDefault();
                           }}
                           onChange={e => setQuery(e.target.value)}
                           className={"input"} id="search"/>
                    <div className="fancy-bg"></div>
                    <div className="search">
                        <svg viewBox="0 0 24 24" aria-hidden="true"
                             className="r-14j79pv r-4qtqp9 r-yyyyoo r-1xvli5t r-dnmrzs r-4wgw6l r-f727ji r-bnwqim r-1plcrui r-lrvibr">
                            <g>
                                <path
                                    d="M21.53 20.47l-3.66-3.66C19.195 15.24 20 13.214 20 11c0-4.97-4.03-9-9-9s-9 4.03-9 9 4.03 9 9 9c2.215 0 4.24-.804 5.808-2.13l3.66 3.66c.147.146.34.22.53.22s.385-.073.53-.22c.295-.293.295-.767.002-1.06zM3.5 11c0-4.135 3.365-7.5 7.5-7.5s7.5 3.365 7.5 7.5-3.365 7.5-7.5 7.5-7.5-3.365-7.5-7.5z"></path>
                            </g>
                        </svg>
                    </div>
                    <button className="close-btn" type="reset">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20"
                             fill="currentColor">
                            <path fillRule="evenodd"
                                  d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z"
                                  clipRule="evenodd"></path>
                        </svg>
                    </button>
                </label>
            </form>
            {open && results && (
                <SearchDropdown results={results}/>
            )}
        </div>
    );
}

function SearchDropdown({results}) {
    return (
        <div className={"global-search-dropdown"}>
            <SearchSection title="Events" items={results.events}/>
            <SearchSection title="Clubs" items={results.clubs}/>
            <SearchSection title="Threads" items={results.threads}/>
            <SearchSection title="Posts" items={results.posts}/>
        </div>
    );
}

function SearchSection({title, items}) {
    if (!items || items.length === 0) return null;

    return (
        <>
            <div className={"search-title"}>
                {title}
            </div>

            {items.map(item => (
                <a
                    key={item.id}
                    href={item.url}
                    className={"search-row"}
                >
                    <div>{item.title}</div>
                    {item.subtitle && (
                        <div className={"search-subtitle"}>
                            {item.subtitle}
                        </div>
                    )}
                </a>
            ))}
        </>
    );
}
